package org.jsoup.parser;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.jsoup.parser.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.jsoup.parser.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import org.jsoup.parser.Parser;
import org.jsoup.safety.Whitelist;

import static org.junit.Assert.*;

public class StepDefs {

    private Document document;
    private Element element;
    private String input;

    @Given("the tokenizer is in the RCDATA state processing a {string} element")
    public void the_tokenizer_is_in_the_RCDATA_state_processing_a_element(String elementName) {
        // This step sets up the context for testing RCDATA elements like textarea and title
        // We'll create a document with the element to test
        String html = String.format("<%s></%s>", elementName, elementName);
        this.document = Jsoup.parse(html);
        this.element = document.selectFirst(elementName);
    }

    @When("the input contains {string}")
    public void the_input_contains(String input) {
        this.input = input;
        // Parse the HTML with the input inside the element
        String elementName = element.tagName();
        String html = String.format("<%s>%s</%s>", elementName, input, elementName);
        this.document = Jsoup.parse(html);
        this.element = document.selectFirst(elementName);
    }

    @Then("the {string} text content should be {string}")
    public void the_text_content_should_be(String elementName, String expectedText) {
        Element foundElement = document.selectFirst(elementName);
        assertNotNull("Element " + elementName + " should exist", foundElement);
        String actualText = foundElement.text();
        assertEquals("Text content of " + elementName + " element", expectedText, actualText);
    }

    @Then("the {string} tag should be parsed as a sibling element containing {string}")
    public void the_tag_should_be_parsed_as_a_sibling_element_containing(String tagName, String expectedContent) {
        // Look for the tag as a sibling of the original element
        Element foundTag = document.selectFirst(tagName);
        assertNotNull("Tag " + tagName + " should exist as sibling", foundTag);
        String actualContent = foundTag.text();
        assertEquals("Content of " + tagName + " tag", expectedContent, actualContent);
    }

    @Then("the {string} tag should be parsed as a new element containing {string}")
    public void the_tag_should_be_parsed_as_a_new_element_containing(String tagName, String expectedContent) {
        Element foundTag = document.selectFirst(tagName);
        assertNotNull("Tag " + tagName + " should exist as a new element", foundTag);
        String actualContent = foundTag.text();
        assertEquals("Content of " + tagName + " tag", expectedContent, actualContent);
    }
}

